import{_ as s,o as i,c as t,ae as e}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"macOS \\"应用已损坏\\" 故障排除指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/macos-gatekeeper-fix.md","filePath":"guide/macos-gatekeeper-fix.md"}'),l={name:"guide/macos-gatekeeper-fix.md"};function n(p,a,o,h,r,d){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="macos-应用已损坏-故障排除指南" tabindex="-1">macOS &quot;应用已损坏&quot; 故障排除指南 <a class="header-anchor" href="#macos-应用已损坏-故障排除指南" aria-label="Permalink to &quot;macOS &quot;应用已损坏&quot; 故障排除指南&quot;">​</a></h1><p>由于 macOS 的安全机制（Gatekeeper），未签名的应用在首次打开时可能会提示 <strong>“应用已损坏，无法打开。你应该将它移到废纸篓。”</strong></p><p>这不是应用本身的问题，而是 macOS 对从互联网下载的未签名应用的默认拦截行为。</p><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><p>你需要移除应用的“隔离属性”（Quarantine Attribute）。请按照以下步骤操作：</p><h3 id="方法一-使用右键打开-推荐" tabindex="-1">方法一：使用右键打开（推荐） <a class="header-anchor" href="#方法一-使用右键打开-推荐" aria-label="Permalink to &quot;方法一：使用右键打开（推荐）&quot;">​</a></h3><ol><li>在 <code>应用程序</code> 文件夹中找到 <strong>AIO Hub</strong>。</li><li>按住键盘上的 <code>Control</code> 键，同时<strong>右键点击</strong>应用图标。</li><li>在弹出的菜单中选择 <strong>打开</strong>。</li><li>在随后出现的弹窗中点击 <strong>打开</strong> 按钮。 <blockquote><p>这种方法只需要操作一次，之后就可以正常点击打开了。</p></blockquote></li></ol><h3 id="方法二-使用终端命令-如果方法一无效" tabindex="-1">方法二：使用终端命令（如果方法一无效） <a class="header-anchor" href="#方法二-使用终端命令-如果方法一无效" aria-label="Permalink to &quot;方法二：使用终端命令（如果方法一无效）&quot;">​</a></h3><p>如果上述方法无效，你需要使用终端命令手动修复。</p><ol><li>打开 <strong>终端 (Terminal)</strong> 应用。</li><li>复制以下命令，但<strong>不要立即按回车</strong>：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span></span></code></pre></div><em>(注意：cr 后面有一个空格)</em></li><li>打开 <code>应用程序</code> 文件夹，找到 <strong>AIO Hub</strong> 图标。</li><li>将图标<strong>拖入</strong>终端窗口中。 <blockquote><p>此时终端会自动生成正确的路径，例如：<code>/Applications/AIO\\ Hub.app</code> 或 <code>&quot;/Applications/AIO Hub.app&quot;</code>。</p></blockquote></li><li>现在的完整命令应该看起来像这样：<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/AIO</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Hub.app</span></span></code></pre></div></li><li>按 <strong>回车键</strong> 执行。</li><li>如果提示输入密码（Password），请输入你的开机密码并回车（输入过程中屏幕上不会显示字符，这是正常的）。</li></ol><hr><h2 id="常见错误" tabindex="-1">常见错误 <a class="header-anchor" href="#常见错误" aria-label="Permalink to &quot;常见错误&quot;">​</a></h2><h3 id="❌-错误示范" tabindex="-1">❌ 错误示范 <a class="header-anchor" href="#❌-错误示范" aria-label="Permalink to &quot;❌ 错误示范&quot;">​</a></h3><p>直接复制路径但没有处理空格：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/AIO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Hub.app</span></span></code></pre></div><p><strong>报错信息</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xattr: No such file: /Applications/AIO</span></span>
<span class="line"><span>xattr: No such file: Hub.app</span></span></code></pre></div><p><strong>原因</strong>：终端把空格当成了分隔符，认为你在操作两个不同的文件。</p><h3 id="✅-正确示范" tabindex="-1">✅ 正确示范 <a class="header-anchor" href="#✅-正确示范" aria-label="Permalink to &quot;✅ 正确示范&quot;">​</a></h3><p>使用引号包裹路径，或使用反斜杠转义空格：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/Applications/AIO Hub.app&quot;</span></span></code></pre></div><p>或者</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Applications/AIO</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Hub.app</span></span></code></pre></div>`,23)])])}const g=s(l,[["render",n]]);export{k as __pageData,g as default};
